import{_ as e,o as a,c as i,a as n}from"./chunks/framework.8tiMeCK-.js";const p="/PenguinLab/assets/ch09_fig130.lLgZdASC.webp",g=JSON.parse('{"title":"9.3  配置内核以支持 ftrace","description":"","frontmatter":{},"headers":[],"relativePath":"notes/linux_kernel_debugging/ch09_3.md","filePath":"notes/linux_kernel_debugging/ch09_3.md","lastUpdated":null}'),t={name:"notes/linux_kernel_debugging/ch09_3.md"};function c(r,s,l,o,d,h){return a(),i("div",null,[...s[0]||(s[0]=[n('<h1 id="_9-3-配置内核以支持-ftrace" tabindex="-1">9.3 配置内核以支持 ftrace <a class="header-anchor" href="#_9-3-配置内核以支持-ftrace" aria-label="Permalink to &quot;9.3  配置内核以支持 ftrace&quot;">​</a></h1><p>大多数现代 Linux 发行版都会预置 ftrace 支持到手。</p><p>这很合理——毕竟在出事的时候，你总希望手里有个工具能用，而不是像没头苍蝇一样乱撞。在内核配置项里，这个开关叫做 <code>CONFIG_FTRACE</code>，通常它已经被设为 <code>y</code> 了。如果你习惯用图形化的 <code>make menuconfig</code>，可以在 &quot;Kernel hacking&quot; 下面找到 &quot;Tracers&quot; 菜单。</p><p>不过，开启这个选项有一个前置依赖：<code>TRACING_SUPPORT</code>。</p><p>这跟架构（CPU 类型）有关，而且必须是 <code>y</code>。实际上，你常用的大多数架构（x86, ARM64 等）都已经满足了这个依赖。为了让你有点实感，这里放一张在 x86_64 上 5.10.60 内核的配置截图：</p><p><img src="'+p+`" alt="figure"></p><p>*<em>图 9.3 – x86_64 (5.10.60) 上 Tracers 子菜单的截图（默认选项）</em></p><p>除了主开关，还有一些特定的跟踪器有自己的依赖。比如，如果你想启用 &quot;Interrupts-off Latency Tracer&quot;（<code>CONFIG_IRQSOFF_TRACER</code>），就需要 <code>TRACE_IRQFLAGS_SUPPORT=y</code>（通常这也是默认开启的；我们会在后面的 FAQ 章节里细讲这些专门测延迟的跟踪器）。另外，很多选项需要能显示内核栈回溯（<code>CONFIG_STACKTRACE_SUPPORT=y</code>），好在这些在现代内核里几乎都是标配。</p><p>如果你想刨根问底，所有 ftrace 相关的子菜单和配置项都定义在源码树的 <code>kernel/trace/Kconfig</code> 文件里。你可以去那里翻阅任何你感兴趣的配置项说明。</p><h3 id="你的内核到底开了没" tabindex="-1">你的内核到底开了没？ <a class="header-anchor" href="#你的内核到底开了没" aria-label="Permalink to &quot;你的内核到底开了没？&quot;">​</a></h3><p>理论说完了，实际问题来了：你手上的系统到底有没有开 ftrace？</p><p>如果是像 Ubuntu 20.04.3 LTS 这种通用发行版，答案几乎肯定是肯定的。我们可以验证一下：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">$</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> grep</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -w</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> CONFIG_FTRACE</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /boot/config-5.11.0-46-generic</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> </span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">CONFIG_FTRACE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">y</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>看，是 <code>y</code>。</p><p>那如果你搞的是嵌入式项目呢？这就不好说了。去翻翻你的项目里的内核配置文件，或者直接 <code>grep</code> 一下。在我工作的这个定制的 5.10.60 生产内核上，它是开着的。</p><p>顺便说一句，本书的技术审稿人 Chi Thahn Hoang 在嵌入式 Linux 领域经验非常丰富。他提到一个很关键的经验：<strong>在他经手的项目里，ftrace 总是会被编译进内核</strong>。为什么？因为虽然你平时不用它，但当系统出问题时，它简直是救命稻草。而且，只要你不去「打开」它，它的开销就是零。</p><p>这就引出了下一个问题：开销。</p><h3 id="ftrace-和系统开销" tabindex="-1">Ftrace 和系统开销 <a class="header-anchor" href="#ftrace-和系统开销" aria-label="Permalink to &quot;Ftrace 和系统开销&quot;">​</a></h3><p>你可能会想：「即使我不打开它，只要功能在那里，总归有点性能损耗吧？」</p><p>这种直觉是对的，但也不对。如果 ftrace 只是简单的「开启/关闭」，那为了跟踪每一个函数的入口和出口，代码里确实得到处埋下这种判断逻辑：</p><div class="language-c vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">c</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">if</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (tracing_enabled) {</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    // 做跟踪记录的事情</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>如果是这样，即便你不跟踪，每个函数调用都要多跑一个 <code>if</code> 判断。在内核这种每纳秒必争的地方，这种开销是不可接受的。</p><p>但内核开发者们想到了一个绝妙（甚至有点疯狂）的解决方案。</p><p>这个配置叫 <strong><code>CONFIG_DYNAMIC_FTRACE</code></strong>（动态 ftrace）。</p><p>当它开启时，内核会在运行时做一些惊人的事情——它会直接修改内存中的机器码。在跟踪关闭的时候，它把函数入口处的指令替换成 <code>NOP</code>（空操作），什么都不做，完全没有性能损耗。当你需要跟踪某个函数时，它会动态地把那段指令改成一个跳转，跳转到 ftrace 的处理代码（这通常被称为 <strong>Trampoline</strong>，蹦床机制）。</p><p>所以，默认情况下，这个选项是开启的。这意味着：</p><ol><li>不跟踪时，性能是原生的。</li><li>跟踪少量函数时，性能接近原生。</li><li>只有在全速跟踪所有函数时，才会有明显的性能下降。</li></ol><hr><p>接下来，我们要进入正题了。假设你的内核已经配置妥当，我们现在直接切入 <code>/sys/kernel/tracing</code> 目录，去拨弄那些控制开关。</p><blockquote><p><strong>注意</strong>：接下来的操作都需要 root 权限。如果你不是 root 用户，很多文件会是只读的，或者无法读取。</p></blockquote><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># cd /sys/kernel/tracing</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>（第一次用我们显式写出来这个路径。注意那个 <code>#</code> 提示符，这暗示我们现在是以 root 身份运行的；你需要 <code>sudo -s</code> 或者在每个命令前加 <code>sudo</code>。）</p><p><code>tracefs</code> 这个文件系统里有很多控制旋钮（当然都是伪文件，就像 <code>procfs</code> 和 <code>sysfs</code> 一样）。其中有一个名叫 <code>tracing_on</code> 的文件，它控制着跟踪功能的实际开关。</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># ls -l tracing_on </span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">-rw-r--r--</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> root</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> root</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Jan</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 19</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 19:00</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tracing_on</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>它现在的值是多少？</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># cat tracing_on </span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">1</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>是 <code>1</code>。这很直观——<code>0</code> 表示关闭，<code>1</code> 表示开启。</p><p><strong>等一下，ftrace 默认是开着的？这不会影响性能吗？</strong></p><p>不用担心，这里有个微妙的细节。虽然 <code>tracing_on</code> 是 <code>1</code>，但 ftrace 实际上处于「待机」状态。</p><p>你可以把 <code>tracing_on</code> 理解为总闸，但还需要确认当前的 <code>current_tracer</code>（当前跟踪器）是什么。如果它是 <code>nop</code>（即 No Operation），那就意味着虽然总闸推上去了，但并没有安装任何实际的跟踪探头，所以系统依然在以原生速度运行。</p><p>这就像你把电灯开关打开了，但灯泡里没装灯丝——电流不会流过，当然也不会发光，更不会费电。</p><p>这就是 <code>CONFIG_DYNAMIC_FTRACE</code> 带来的好处：只有当你真正指定了一个跟踪器（比如 <code>function_graph</code>），内核才会开始修改指令，把「灯丝」装上去。在那之前，这一切都是静态的、零损耗的。</p>`,42)])])}const u=e(t,[["render",c]]);export{g as __pageData,u as default};
